/**
 * Runtime merge of fact-locked editorial overlays onto player/team rows.
 * Sidecar JSON is generated by enrich:* scripts — never invent facts here.
 */

import playerOverlayData from './playerEditorialOverlays.json' with { type: 'json' };
import teamOverlayData from './teamEditorialOverlays.json' with { type: 'json' };

const playerOverlays = playerOverlayData?.overlays ?? {};
const teamOverlays = teamOverlayData?.overlays ?? {};

const PLAYER_FIELDS = [
  'quickFact',
  'playStyleSummary',
  'playingStyle',
  'strengths',
  'keyStrengths',
  'knownFor',
  'quizHints',
  'roleSummary',
  'careerContext',
];

const TEAM_FIELDS = [
  'shortHistory',
  'fanGuide',
  'metaDescription',
  'tacticalIdentity',
  'stadiumContext',
  'leagueContext',
  'rivalsSummary',
  'legendsSummary',
  'playersToKnowIntro',
  'quizDiscoveryLead',
];

function pickOverlay(base, overlay, fields) {
  if (!overlay) return base;
  const next = { ...base };
  for (const key of fields) {
    const value = overlay[key];
    if (value == null) continue;
    if (Array.isArray(value) && value.length === 0) continue;
    if (typeof value === 'string' && !value.trim()) continue;
    next[key] = value;
  }
  return next;
}

export function mergePlayerOverlay(player) {
  if (!player?.id) return player;
  return pickOverlay(player, playerOverlays[player.id], PLAYER_FIELDS);
}

export function mergeTeamOverlay(team) {
  if (!team?.id) return team;
  return pickOverlay(team, teamOverlays[team.id], TEAM_FIELDS);
}

export function hasPlayerOverlay(playerId) {
  return Boolean(playerOverlays[playerId]);
}

export function hasTeamOverlay(teamId) {
  return Boolean(teamOverlays[teamId]);
}
